def avg_abs_dev(nums):
    if not nums: return 0.0
    mean = sum(nums) / len(nums)
    return sum(abs(x - mean) for x in nums) / len(nums)

if __name__ == "__main__":
    print(f"AAD: {avg_abs_dev([4, 1, 3, 2])}")
